<?php
declare(strict_types=1); namespace GK\CPF\Dependency; use GK\CPF\Core\{JsonStore,CpfException,CpfNodeManager};
final class CpfDependencyManager {public function __construct(private JsonStore$s=new JsonStore(),private CpfNodeManager$n=new CpfNodeManager()){} public function add(string$d,string$source,string$target,string$type,string$impact):array{$this->n->get($d,$source);$this->n->get($d,$target);if(!in_array($impact,['LOW','MEDIUM','HIGH','CRITICAL'],true))throw new CpfException('IMPACT_INVALID','Invalid impact',4);$list=$this->s->read("$d/dependencies/dependencies.json",[]);foreach($list as$x)if($x['source_node_id']===$source&&$x['target_node_id']===$target&&$x['dependency_type']===$type)return$x;$r=['dependency_id'=>sprintf('DEP_%06d',count($list)+1),'source_node_id'=>$source,'target_node_id'=>$target,'dependency_type'=>$type,'impact_level'=>$impact];$list[]=$r;$this->s->write("$d/dependencies/dependencies.json",$list);return$r;} public function impact(string$d,string$id):array{$all=$this->s->read("$d/dependencies/dependencies.json",[]);$seen=[];$q=[$id];$out=[];while($q){$cur=array_shift($q);foreach($all as$e)if($e['source_node_id']===$cur&&!isset($seen[$e['target_node_id']])){$seen[$e['target_node_id']]=1;$out[]=$e;$q[]=$e['target_node_id'];}}return$out;} public function all(string$d):array{return$this->s->read("$d/dependencies/dependencies.json",[]);} }